define([],function(){var activeFilters={};var searchQuery="";function normalizeText(str){return str.normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase()}function initSearch(container){var input=container.querySelector(".dims-block-search-input");var clearBtn=container.querySelector(".dims-block-search-clear");if(!input){return}var debounceTimer=null;input.addEventListener("input",function(){if(clearBtn){clearBtn.style.display=input.value.length>0?"flex":"none"}clearTimeout(debounceTimer);debounceTimer=setTimeout(function(){searchQuery=normalizeText(input.value.trim());applyFilters(container)},100)});if(clearBtn){clearBtn.addEventListener("click",function(){input.value="";clearBtn.style.display="none";input.focus();searchQuery="";applyFilters(container)})}}function init(){var container=document.querySelector(".block-dimensions-content");if(!container){return}initSearch(container);container.addEventListener("click",function(e){var tab=e.target.closest(".dims-filter-tab");if(!tab){return}var field=tab.getAttribute("data-filter-field");var value=tab.getAttribute("data-filter-value");var group=tab.closest("[data-filter-group]");if(group){var tabs=group.querySelectorAll(".dims-filter-tab");tabs.forEach(function(t){t.classList.remove("active");t.setAttribute("aria-selected","false")})}tab.classList.add("active");tab.setAttribute("aria-selected","true");activeFilters[field]=value;applyFilters(container)});container.addEventListener("change",function(e){var select=e.target.closest(".dims-filter-select");if(!select){return}var field=select.getAttribute("data-filter-field");var value=select.value;activeFilters[field]=value;applyFilters(container)})}function applyFilters(container){var filtersByType={};for(var field in activeFilters){if(!activeFilters.hasOwnProperty(field)){continue}var parts=field.split("_");var type=parts[0];if(!filtersByType[type]){filtersByType[type]={}}filtersByType[type][field]=activeFilters[field]}var cardLists=container.querySelectorAll("[data-cards-type]");cardLists.forEach(function(list){var type=list.getAttribute("data-cards-type");var typeFilters=filtersByType[type]||{};var items=list.querySelectorAll(".dims-card-item");items.forEach(function(item){var visible=true;for(var field in typeFilters){if(!typeFilters.hasOwnProperty(field)){continue}var filterValue=typeFilters[field];if(!filterValue){continue}var attrName="data-"+field.replace(/_/g,"-");var cardValue=item.getAttribute(attrName);if(cardValue!==filterValue){visible=false;break}}if(visible&&searchQuery.length>0){var title=item.querySelector(".card-title");if(title){visible=normalizeText(title.textContent).indexOf(searchQuery)!==-1}}if(visible){item.classList.remove("dims-card-hidden");item.style.display=""}else{item.classList.add("dims-card-hidden");item.style.display="none"}})})}return{init:init}});